   240→    public Optional<LogToClean> grabFilthiestCompactedLog(Time time, PreCleanStats preCleanStats) {
   241→        return inLock(lock, () -> {
   242→            long now = time.milliseconds();
   243→            timeOfLastRun = now;
   244→            Map<TopicPartition, Long> lastClean = allCleanerCheckpoints();
   245→
   246→            List<LogToClean> dirtyLogs = logs.entrySet().stream()
   247→                    .filter(entry -> entry.getValue().config().compact &&
   248→                            !inProgress.containsKey(entry.getKey()) &&
   249→                            !isUncleanablePartition(entry.getValue(), entry.getKey())
   250→                    )
   251→                    .map(entry -> {
   252→                                // create a LogToClean instance for each
   253→                                TopicPartition topicPartition = entry.getKey();
   254→                                UnifiedLog log = entry.getValue();
   255→                                try {
   256→                                    Long lastCleanOffset = lastClean.get(topicPartition);
   257→                                    OffsetsToClean offsetsToClean = cleanableOffsets(log, Optional.ofNullable(lastCleanOffset), now);
   258→                                    // update checkpoint for logs with invalid checkpointed offsets
   259→                                    if (offsetsToClean.forceUpdateCheckpoint) {
   260→                                        updateCheckpoints(log.parentDirFile(), Optional.of(Map.entry(topicPartition, offsetsToClean.firstDirtyOffset)), Optional.empty());
   261→                                    }
   262→                                    long compactionDelayMs = maxCompactionDelay(log, offsetsToClean.firstDirtyOffset, now);
   263→                                    preCleanStats.updateMaxCompactionDelay(compactionDelayMs);
   264→
   265→                                    return new LogToClean(log, offsetsToClean.firstDirtyOffset,
   266→                                            offsetsToClean.firstUncleanableDirtyOffset, compactionDelayMs > 0);
   267→                                } catch (Throwable e) {
   268→                                    throw new LogCleaningException(log, "Failed to calculate log cleaning stats for partition " + topicPartition, e);
   269→                                }
   270→                            }
   271→                    )
   272→                    .filter(ltc -> ltc.totalBytes() > 0) // skip any empty logs
   273→                    .toList();
